const express = require('express');
const axios = require('axios');
const crypto = require('crypto');
const winston = require('winston');

const app = express();
app.use(express.json());

// Secure logger that redacts sensitive information
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.printf(({ timestamp, level, message, ...meta }) => {
      // Redact sensitive data from logs
      const sanitizedMeta = JSON.stringify(meta).replace(
        /"(api_key|authorization|password|token)":\s*"[^"]*"/gi,
        '"$1":"[REDACTED]"'
      );
      return `${timestamp} [${level}]: ${message} ${sanitizedMeta}`;
    })
  ),
  transports: [
    new winston.transports.File({ filename: 'api-gateway.log' }),
    new winston.transports.Console()
  ]
});

// Secure API key storage (in production, use environment variables or secret management service)
const VALID_API_KEYS = new Map([
  [crypto.createHash('sha256').update('key123').digest('hex'), { 
    name: 'service-a', 
    allowedServices: ['service1', 'service2'] 
  }],
  [crypto.createHash('sha256').update('key456').digest('hex'), { 
    name: 'service-b', 
    allowedServices: ['service1'] 
  }]
]);

// Allowlist of backend services
const BACKEND_SERVICES = {
  'service1': 'http://localhost:3001',
  'service2': 'http://localhost:3002'
};

// Rate limiting map
const rateLimitMap = new Map();
const RATE_LIMIT_WINDOW = 60000; // 1 minute
const RATE_LIMIT_MAX_REQUESTS = 100;

// Middleware: API Key Authentication
function authenticateApiKey(req, res, next) {
  const apiKey = req.query.api_key;
  
  if (!apiKey) {
    logger.warn('Authentication failed: Missing API key', {
      ip: req.ip,
      path: req.path
    });
    return res.status(401).json({ error: 'API key required' });
  }

  // Validate API key format (alphanumeric, reasonable length)
  if (!/^[a-zA-Z0-9]{6,64}$/.test(apiKey)) {
    logger.warn('Authentication failed: Invalid API key format', {
      ip: req.ip,
      path: req.path
    });
    return res.status(401).json({ error: 'Invalid API key format' });
  }

  // Hash the API key for lookup
  const hashedKey = crypto.createHash('sha256').update(apiKey).digest('hex');
  const keyData = VALID_API_KEYS.get(hashedKey);

  if (!keyData) {
    logger.warn('Authentication failed: Invalid API key', {
      ip: req.ip,
      path: req.path
    });
    return res.status(401).json({ error: 'Invalid API key' });
  }

  // Rate limiting
  const now = Date.now();
  const clientId = hashedKey;
  
  if (!rateLimitMap.has(clientId)) {
    rateLimitMap.set(clientId, []);
  }
  
  const requests = rateLimitMap.get(clientId).filter(time => now - time < RATE_LIMIT_WINDOW);
  
  if (requests.length >= RATE_LIMIT_MAX_REQUESTS) {
    logger.warn('Rate limit exceeded', {
      client: keyData.name,
      ip: req.ip
    });
    return res.status(429).json({ error: 'Rate limit exceeded' });
  }
  
  requests.push(now);
  rateLimitMap.set(clientId, requests);

  // Attach authenticated client info to request
  req.authenticatedClient = keyData;
  req.hashedApiKey = hashedKey;
  
  next();
}

// Middleware: Service Authorization
function authorizeService(req, res, next) {
  const serviceName = req.params.service;
  
  if (!serviceName || !/^[a-z0-9-]+$/.test(serviceName)) {
    logger.warn('Invalid service name', {
      client: req.authenticatedClient.name,
      service: serviceName
    });
    return res.status(400).json({ error: 'Invalid service name' });
  }

  if (!BACKEND_SERVICES[serviceName]) {
    logger.warn('Service not found', {
      client: req.authenticatedClient.name,
      service: serviceName
    });
    return res.status(404).json({ error: 'Service not found' });
  }

  if (!req.authenticatedClient.allowedServices.includes(serviceName)) {
    logger.warn('Access denied to service', {
      client: req.authenticatedClient.name,
      service: serviceName
    });
    return res.status(403).json({ error: 'Access denied to this service' });
  }

  next();
}

// Proxy endpoint
app.all('/api/:service/*', authenticateApiKey, authorizeService, async (req, res) => {
  const serviceName = req.params.service;
  const path = req.params[0];
  const backendUrl = BACKEND_SERVICES[serviceName];

  // Validate and sanitize path
  if (path.includes('..') || path.includes('//')) {
    logger.warn('Path traversal attempt detected', {
      client: req.authenticatedClient.name,
      path: path
    });
    return res.status(400).json({ error: 'Invalid path' });
  }

  const targetUrl = `${backendUrl}/${path}`;

  // Remove api_key from query params before forwarding
  const forwardQuery = { ...req.query };
  delete forwardQuery.api_key;

  // Create secure headers for backend
  const headers = {
    'X-API-Client': req.authenticatedClient.name,
    'X-Forwarded-For': req.ip,
    'X-Request-ID': crypto.randomUUID(),
    'Content-Type': req.headers['content-type'] || 'application/json'
  };

  // Log request (with redacted sensitive data)
  logger.info('Proxying request', {
    client: req.authenticatedClient.name,
    method: req.method,
    service: serviceName,
    path: path,
    requestId: headers['X-Request-ID']
  });

  try {
    const response = await axios({
      method: req.method,
      url: targetUrl,
      params: forwardQuery,
      data: req.body,
      headers: headers,
      timeout: 30000,
      maxRedirects: 0,
      validateStatus: () => true
    });

    logger.info('Request completed', {
      client: req.authenticatedClient.name,
      requestId: headers['X-Request-ID'],
      statusCode: response.status
    });

    res.status(response.status).json(response.data);
  } catch (error) {
    logger.error('Proxy error', {
      client: req.authenticatedClient.name,
      requestId: headers['X-Request-ID'],
      error: error.message
    });

    if (error.code === 'ECONNREFUSED') {
      return res.status(503).json({ error: 'Service unavailable' });
    }

    res.status(500).json({ error: 'Internal gateway error' });
  }
});

